-- UniBookClub Base Seed
-- Matches simplified schema: faculties.name, majors.name, courses.name
-- Safe to run multiple times.

-- =====================================================
-- FACULTIES
-- =====================================================
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name;

-- =====================================================
-- MAJORS
-- =====================================================
ON CONFLICT (id) DO UPDATE SET
  faculty_id = EXCLUDED.faculty_id,
  name = EXCLUDED.name;

-- =====================================================
-- COURSES
-- =====================================================
ON CONFLICT (id) DO UPDATE SET
  major_id = EXCLUDED.major_id,
  name = EXCLUDED.name;
